def read_requirements():
    requirements = []
    try:
        with open('requirements.txt', 'r') as f:
            requirements = [line.strip() for line in f if line.strip() and not line.startswith('#')]
    except FileNotFoundError:
        requirements = [
            'requests>=2.25.0',
            'numpy>=1.19.0',
            'pandas>=1.2.0',
        ]
    return requirements


